function reducer(state, action) {
  switch (action.type) {
    case "add":
      return { count: state.count + action.n };
    case "reset":
      return { count: 0 };
    default:
      return state;
  }
}

let s = { count: 0 };
s = reducer(s, { type: "add", n: 5 });
s = reducer(s, { type: "add", n: 3 });
console.log(s.count);

